  1→/**
  2→ * Tests for Sequant MCP Server
  3→ * Issue #372: Expose Sequant Workflow as MCP Server
  4→ *
  5→ * Covers:
  6→ * - AC-1: Server creation and initialization
  7→ * - AC-2: sequant_run tool schema and validation
  8→ * - AC-3: sequant_status tool schema and validation
  9→ * - AC-4: sequant_logs tool schema and validation
 10→ * - AC-5: sequant://state resource
 11→ * - AC-6: sequant://config resource
 12→ * - AC-13: Tool schemas match specification
 13→ * - AC-14: Structured MCP errors for invalid inputs
 14→ *
 15→ * Guarded: Skips if @modelcontextprotocol/sdk is not installed (#396)
 16→ */
 17→
 18→import { describe, it, expect, beforeEach, afterEach } from "vitest";
 19→
 20→// Check if MCP SDK is available (dynamic import to avoid hard failure)
 21→const mcpSdkAvailable = await import("@modelcontextprotocol/sdk/server/mcp.js")
 22→  .then(() => true)
 23→  .catch(() => false);
 24→
 25→describe.skipIf(!mcpSdkAvailable)("Sequant MCP Server", () => {
 26→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
 27→  let client: any;
 28→  let cleanup: () => Promise<void>;
 29→
 30→  beforeEach(async () => {
 31→    const { createServer } = await import("./server.js");
 32→    const { Client } =
 33→      await import("@modelcontextprotocol/sdk/client/index.js");
 34→    const { InMemoryTransport } =
 35→      await import("@modelcontextprotocol/sdk/inMemory.js");
 36→
 37→    const server = createServer("1.0.0-test");
 38→    const clientInstance = new Client({
 39→      name: "test-client",
 40→      version: "1.0.0",
 41→    });
 42→
 43→    const [clientTransport, serverTransport] =
 44→      InMemoryTransport.createLinkedPair();
 45→    await Promise.all([
 46→      clientInstance.connect(clientTransport),
 47→      server.connect(serverTransport),
 48→    ]);
 49→
 50→    client = clientInstance;
 51→    cleanup = async () => {
 52→      await clientInstance.close();
 53→      await server.close();
 54→    };
 55→  });
 56→
 57→  afterEach(async () => {
 58→    await cleanup();
 59→  });
 60→
 61→  // AC-13: Tool schemas match specification
 62→  describe("AC-13: tools/list", () => {
 63→    it("should list all three tools with correct names", async () => {
 64→      const result = await client.listTools();
 65→      const toolNames = result.tools
 66→        .map((t: { name: string }) => t.name)
 67→        .sort();
 68→
 69→      expect(toolNames).toEqual([
 70→        "sequant_logs",
 71→        "sequant_run",
 72→        "sequant_status",
 73→      ]);
 74→    });
 75→
 76→    it("sequant_run should have correct input schema", async () => {
 77→      const result = await client.listTools();
 78→      const runTool = result.tools.find(
 79→        (t: { name: string }) => t.name === "sequant_run",
 80→      );
 81→
 82→      expect(runTool).toBeDefined();
 83→      expect(runTool!.description).toContain("workflow phases");
 84→
 85→      const schema = runTool!.inputSchema;
 86→      expect(schema.properties).toHaveProperty("issues");
 87→      expect(schema.properties).toHaveProperty("phases");
 88→      expect(schema.properties).toHaveProperty("qualityLoop");
 89→      expect(schema.required).toContain("issues");
 90→    });
 91→
 92→    it("sequant_status should have correct input schema", async () => {
 93→      const result = await client.listTools();
 94→      const statusTool = result.tools.find(
 95→        (t: { name: string }) => t.name === "sequant_status",
 96→      );
 97→
 98→      expect(statusTool).toBeDefined();
 99→      expect(statusTool!.description).toContain("workflow state");
100→
101→      const schema = statusTool!.inputSchema;
102→      expect(schema.properties).toHaveProperty("issue");
103→      expect(schema.required).toContain("issue");
104→    });
105→
106→    it("sequant_logs should have correct input schema", async () => {
107→      const result = await client.listTools();
108→      const logsTool = result.tools.find(
109→        (t: { name: string }) => t.name === "sequant_logs",
110→      );
111→
112→      expect(logsTool).toBeDefined();
113→      expect(logsTool!.description).toContain("run logs");
114→
115→      const schema = logsTool!.inputSchema;
116→      expect(schema.properties).toHaveProperty("runId");
117→      expect(schema.properties).toHaveProperty("limit");
118→    });
119→  });
120→
121→  // AC-5, AC-6: Resources
122→  describe("AC-5, AC-6: resources/list", () => {
123→    it("should list state and config resources", async () => {
124→      const result = await client.listResources();
125→      const uris = result.resources.map((r: { uri: string }) => r.uri).sort();
126→
127→      expect(uris).toEqual(["sequant://config", "sequant://state"]);
128→    });
129→
130→    it("sequant://state resource should return JSON", async () => {
131→      const result = await client.readResource({
132→        uri: "sequant://state",
133→      });
134→
135→      expect(result.contents).toHaveLength(1);
136→      expect(result.contents[0].mimeType).toBe("application/json");
137→
138→      // Should be valid JSON
139→      const parsed = JSON.parse(result.contents[0].text as string);
