171→  });
172→
173→  // AC-4: sequant_logs tool
174→  describe("AC-4: sequant_logs", () => {
175→    it("should return empty logs when no log directory exists", async () => {
176→      const result = await client.callTool({
177→        name: "sequant_logs",
178→        arguments: { limit: 5 },
179→      });
180→
181→      expect(result.content).toHaveLength(1);
182→      const data = JSON.parse(
183→        (result.content as Array<{ type: string; text: string }>)[0].text,
184→      );
185→      // Should either have empty logs array or a message
186→      expect(data).toBeDefined();
187→      if (data.logs) {
188→        expect(Array.isArray(data.logs)).toBe(true);
189→      }
190→    });
191→  });
192→
193→  // AC-14: Structured MCP errors
194→  describe("AC-14: structured errors", () => {
195→    it("sequant_run should return structured error for empty issues array", async () => {
196→      const result = await client.callTool({
197→        name: "sequant_run",
198→        arguments: { issues: [] },
199→      });
200→
